    op: 'eq' | 'neq' | 'in' | 'not_in' | 'gt' | 'gte' | 'lt' | 'lte' | 'contains' | 'regex' | 'semver_gt' | 'semver_gte' | 'semver_lt' | 'semver_lte' | 'gate_pass' | 'exp_in';
